import{f as p,D as i,o as s,c as A,a2 as n,b as e,w as t,a as o,G as l,a5 as d}from"./chunks/framework.DHYrF-q6.js";const m=JSON.parse('{"title":"AI 产品设计","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/product-design.md","filePath":"ai-product-manager/product-design.md","lastUpdated":1781090728000}'),E={name:"ai-product-manager/product-design.md"};function u(h,a,c,b,g,q){const r=i("Mermaid");return s(),A("div",null,[a[2]||(a[2]=n('<h1 id="ai-产品设计" tabindex="-1">AI 产品设计 <a class="header-anchor" href="#ai-产品设计" aria-label="Permalink to &quot;AI 产品设计&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>AI 产品的设计哲学与传统产品存在本质差异——<strong>你需要在不确定性中构建用户体验</strong>。传统产品的&quot;确定按钮就是确定&quot;在 AI 产品中变成了&quot;模型的回答有 90% 准确率，你该如何让用户接受另外 10% 的不准确&quot;。本章从需求分析、概率化 UX、评估指标、PRD 规范四个维度，建立 AI 产品设计的核心能力。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>掌握 AI 产品需求挖掘方法、概率化 UX 设计原则、评估指标体系构建，并能独立撰写一份 AI 产品 PRD。</p></div><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',6)),(s(),e(d,null,{default:t(()=>[l(r,{id:"mermaid-18",class:"mermaid",graph:"mindmap%0A%20%20root((AI%20%E4%BA%A7%E5%93%81%E8%AE%BE%E8%AE%A1))%0A%20%20%20%20%E9%9C%80%E6%B1%82%E5%88%86%E6%9E%90%0A%20%20%20%20%20%20AI%20%E9%80%82%E7%94%A8%E6%80%A7%E5%88%A4%E6%96%AD%E7%9F%A9%E9%98%B5%0A%20%20%20%20%20%20%E9%9C%80%E6%B1%82%E8%BD%AC%E5%8C%96%E4%B8%BA%E8%BE%93%E5%85%A5%2F%E8%BE%93%E5%87%BA%0A%20%20%20%20%20%20%E6%8A%80%E6%9C%AF%E5%8F%AF%E8%A1%8C%E6%80%A7%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20ROI%20%E9%A2%84%E4%BC%B0%E4%B8%8E%E4%BC%98%E5%85%88%E7%BA%A7%0A%20%20%20%20%E6%A6%82%E7%8E%87%E5%8C%96%20UX%20%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20%E4%B8%8D%E7%A1%AE%E5%AE%9A%E6%80%A7%E7%AE%A1%E7%90%86%0A%20%20%20%20%20%20%E4%B8%89%E7%BA%A7%E9%99%8D%E7%BA%A7%E7%AD%96%E7%95%A5%0A%20%20%20%20%20%20%E4%BA%BA%E6%9C%BA%E5%8D%8F%E5%90%8C%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20Fallback%20%E6%9C%BA%E5%88%B6%0A%20%20%20%20%E8%AF%84%E4%BC%B0%E6%8C%87%E6%A0%87%E4%BD%93%E7%B3%BB%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E6%80%A7%E8%83%BD%E6%8C%87%E6%A0%87%0A%20%20%20%20%20%20%E4%B8%9A%E5%8A%A1%E6%8C%87%E6%A0%87%0A%20%20%20%20%20%20%E7%94%A8%E6%88%B7%E4%BD%93%E9%AA%8C%E6%8C%87%E6%A0%87%0A%20%20%20%20%20%20A%2FB%20%E6%B5%8B%E8%AF%95%E8%AE%BE%E8%AE%A1%0A%20%20%20%20AI%20%E4%BA%A7%E5%93%81%20PRD%20%E8%A7%84%E8%8C%83%0A%20%20%20%20%20%20PRD%20%E7%BB%93%E6%9E%84%E6%A8%A1%E6%9D%BF%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E9%9C%80%E6%B1%82%E7%AB%A0%E8%8A%82%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E9%9C%80%E6%B1%82%E8%AF%B4%E6%98%8E%0A%20%20%20%20%20%20%E8%AF%84%E4%BC%B0%E6%A0%87%E5%87%86%E5%AE%9A%E4%B9%89%0A"})]),fallback:t(()=>[...a[0]||(a[0]=[o(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=n('<hr><h2 id="二、ai-产品需求分析" tabindex="-1">二、AI 产品需求分析 <a class="header-anchor" href="#二、ai-产品需求分析" aria-label="Permalink to &quot;二、AI 产品需求分析&quot;">​</a></h2><h3 id="_2-1-ai-适用性判断矩阵" tabindex="-1">2.1 AI 适用性判断矩阵 <a class="header-anchor" href="#_2-1-ai-适用性判断矩阵" aria-label="Permalink to &quot;2.1 AI 适用性判断矩阵&quot;">​</a></h3><p>不是所有问题都适合用 AI 解决。作为 AI PM，你的第一项核心能力是判断<strong>这个需求用 AI 做是否划算</strong>。</p><table tabindex="0"><thead><tr><th>判断维度</th><th>适合用 AI</th><th>不适合用 AI</th><th>边界模糊时怎么办</th></tr></thead><tbody><tr><td><strong>数据可得性</strong></td><td>有历史积累的标注数据，或能低成本获取</td><td>数据涉及隐私、合规红线、或完全从零收集</td><td>先做小规模数据采集实验，看质量和成本</td></tr><tr><td><strong>问题确定性</strong></td><td>规则复杂多变、难以穷举</td><td>规则简单明确、if/else 就能搞定</td><td>算一下规则实现和模型训练的研发成本对比</td></tr><tr><td><strong>错误容忍度</strong></td><td>允许一定比例的错误（推荐、客服）</td><td>零容忍错误（医疗处方、金融交易）</td><td>设计&quot;AI 初筛 + 人工复核&quot;流程</td></tr><tr><td><strong>规模效应</strong></td><td>处理量大、人工成本高</td><td>总处理量很小、人工就能搞定</td><td>算 ROI：AI 成本 vs 人工成本 × 处理量</td></tr><tr><td><strong>场景可复现</strong></td><td>场景相对稳定，输入输出模式清晰</td><td>每次都不一样，很难抽象出规律</td><td>先限定场景再扩展</td></tr></tbody></table><details class="details custom-block"><summary>实战案例：什么时候不应该用 AI？</summary><p>我们之前做过一个企业内部的知识库问答项目。业务方最开始提的需求是&quot;做一个 AI 问答机器人，回答员工关于 HR 政策的任何问题&quot;。</p><p>问题在于——HR 政策的&quot;答案&quot;很多是模糊的。&quot;试用期多久&quot;有明确答案，&quot;我的这个情况能不能报销&quot;就完全是 Case-by-case 的判断。AI 可以回答前者，但后者需要人工判断。</p><p>正确的做法是：把需求拆成&quot;确定性问答&quot;（AI 自动回复）和&quot;模糊咨询&quot;（AI 收集必要信息后转人工）。这样 AI 做的是它擅长的，而不是硬做它不擅长的。<strong>不是所有自然语言理解需求都值得用 AI——如果规则就能覆盖 80%，用规则可能更划算。</strong></p></details><h3 id="_2-2-将业务需求转化为模型输入-输出" tabindex="-1">2.2 将业务需求转化为模型输入/输出 <a class="header-anchor" href="#_2-2-将业务需求转化为模型输入-输出" aria-label="Permalink to &quot;2.2 将业务需求转化为模型输入/输出&quot;">​</a></h3><p>这是 AI PM 最核心的&quot;翻译&quot;能力。</p><p><strong>原始业务需求</strong>：帮用户找到合适的金融产品。</p><p><strong>拆解后的模型输入/输出定义</strong>：</p><table tabindex="0"><thead><tr><th>要素</th><th>定义</th></tr></thead><tbody><tr><td><strong>输入</strong></td><td>用户画像向量（年龄/收入/风险偏好/资产规模）+ 交互上下文（当前查看的产品类别）</td></tr><tr><td><strong>输出</strong></td><td>推荐产品列表（top-5），每条附带推荐理由（可解释性）和匹配度分数（置信度）</td></tr><tr><td><strong>样本量</strong></td><td>预估需要 500 万+ 用户行为日志作为训练数据</td></tr><tr><td><strong>重要约束</strong></td><td>推荐结果中不能出现超出用户风险承受能力的金融产品（合规硬约束）</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">面试追问</p><p><strong>Q: 业务方说&quot;帮我用 AI 提升用户体验&quot;，你怎么拆？</strong></p><p><strong>A:</strong> &quot;提升用户体验&quot;这个需求太模糊了，我一定会追问三个问题：</p><ol><li><p><strong>具体指标是什么？</strong>——是 NPS 提升 10%？还是客服人工转接率降低 20%？还是用户平均停留时长增加？没有量化目标的需求没法评估效果。</p></li><li><p><strong>用户的核心痛点是什么？</strong>——是信息过载（需要推荐）？是查找效率低（需要搜索）？是决策困难（需要对比分析）？不同痛点对应不同的 AI 方案。</p></li><li><p><strong>可接受的成本/周期是多少？</strong>——如果是两周内要上线，那大概率只能用现有模型 API + 简单 Prompt；如果愿意花三个月自研，可以考虑精调模型。方案的天花板取决于资源。</p></li></ol></div><hr><h2 id="三、概率化-ux-设计" tabindex="-1">三、概率化 UX 设计 <a class="header-anchor" href="#三、概率化-ux-设计" aria-label="Permalink to &quot;三、概率化 UX 设计&quot;">​</a></h2><h3 id="_3-1-不确定性管理的核心原则" tabindex="-1">3.1 不确定性管理的核心原则 <a class="header-anchor" href="#_3-1-不确定性管理的核心原则" aria-label="Permalink to &quot;3.1 不确定性管理的核心原则&quot;">​</a></h3><p>传统产品的用户心智是&quot;我点这个按钮，就一定会发生这件事&quot;。AI 产品打破了这层确定性——用户说一句话，模型的回答可能是对的也可能是错的。</p><p><strong>三个核心设计原则</strong>：</p><ol><li><p><strong>不伪装确定性</strong>：不要把概率输出包装成确定性结论。不要说&quot;这是最佳方案&quot;，而要说&quot;根据分析，这个方案匹配度最高（92%）&quot;。让用户知道 AI 也有不确定的时候。</p></li><li><p><strong>渐进式置信展示</strong>：高置信度（&gt;95%）→ 直接呈现结果；中置信度（80-95%）→ 展示结果 + 标注&quot;建议核实&quot;；低置信度（&lt;80%）→ 转人工或给多个备选方案。</p></li><li><p><strong>错误成本最小化</strong>：设计时先问&quot;如果模型错了，后果是什么？&quot;——推荐系统推荐了不感兴趣的物品（用户无视就好）vs 医疗 AI 漏诊了早期癌症（可能致命）。前者的错误成本低，设计可以&quot;激进&quot;一点；后者的错误成本极高，必须有严格的复核机制。</p></li></ol><h3 id="_3-2-三级降级策略-fallback" tabindex="-1">3.2 三级降级策略（Fallback） <a class="header-anchor" href="#_3-2-三级降级策略-fallback" aria-label="Permalink to &quot;3.2 三级降级策略（Fallback）&quot;">​</a></h3><p>这是 AI 产品最经典的设计模式：</p>',20)),(s(),e(d,null,{default:t(()=>[l(r,{id:"mermaid-249",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%E7%94%A8%E6%88%B7%E8%BE%93%E5%85%A5%5D%20--%3E%20B%7B%E6%A8%A1%E5%9E%8B%E7%BD%AE%E4%BF%A1%E5%BA%A6%20%3E%2095%25%3F%7D%0A%20%20%20%20B%20--%3E%7C%E6%98%AF%7C%20C%5B%E7%9B%B4%E6%8E%A5%E8%BF%94%E5%9B%9E%20AI%20%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20B%20--%3E%7C%E5%90%A6%7C%20D%7B%E7%9F%A5%E8%AF%86%E5%BA%93%E8%83%BD%E5%8C%B9%E9%85%8D%E5%88%B0%3F%7D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20E%5B%E8%BF%94%E5%9B%9E%E7%9F%A5%E8%AF%86%E5%BA%93%E6%A0%87%E5%87%86%E7%AD%94%E6%A1%88%5D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20F%5B%E8%BD%AC%E4%BA%BA%E5%B7%A5%E5%AE%A2%E6%9C%8D%5D%0A%20%20%20%20C%20--%3E%20G%5B%E7%94%A8%E6%88%B7%E7%9C%8B%E5%88%B0%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20E%20--%3E%20G%0A%20%20%20%20F%20--%3E%20H%5B%E4%BA%BA%E5%B7%A5%E8%B7%9F%E8%BF%9B%5D%0A"})]),fallback:t(()=>[...a[1]||(a[1]=[o(" Loading... ",-1)])]),_:1})),a[4]||(a[4]=n(`<h3 id="_3-3-人机协同设计" tabindex="-1">3.3 人机协同设计 <a class="header-anchor" href="#_3-3-人机协同设计" aria-label="Permalink to &quot;3.3 人机协同设计&quot;">​</a></h3><table tabindex="0"><thead><tr><th>协同模式</th><th>AI 做什么</th><th>人做什么</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>AI 主导</strong></td><td>自动完成决策或操作</td><td>仅在异常时介入</td><td>推荐系统、垃圾邮件过滤</td></tr><tr><td><strong>人主导</strong></td><td>提供建议和辅助信息</td><td>做出最终决策</td><td>医疗诊断、金融投资建议</td></tr><tr><td><strong>人机共诊</strong></td><td>AI 和人独立判断后比对</td><td>不一致时升级处理</td><td>医疗影像判读、法务审查</td></tr></tbody></table><hr><h2 id="四、ai-产品评估指标体系" tabindex="-1">四、AI 产品评估指标体系 <a class="header-anchor" href="#四、ai-产品评估指标体系" aria-label="Permalink to &quot;四、AI 产品评估指标体系&quot;">​</a></h2><h3 id="_4-1-三层评估模型" tabindex="-1">4.1 三层评估模型 <a class="header-anchor" href="#_4-1-三层评估模型" aria-label="Permalink to &quot;4.1 三层评估模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>指标类型</th><th>示例</th><th>责任人</th></tr></thead><tbody><tr><td><strong>L1 模型指标</strong></td><td>技术性能</td><td>准确率、召回率、F1、Perplexity、BLEU</td><td>算法团队</td></tr><tr><td><strong>L2 业务指标</strong></td><td>商业价值</td><td>人工替代率、成本节约、转化率提升</td><td>AI PM</td></tr><tr><td><strong>L3 体验指标</strong></td><td>用户感受</td><td>满意度、任务完成率、NPS</td><td>AI PM</td></tr></tbody></table><p>AI PM 的核心职责是<strong>确保 L1 的提升能翻译成 L2 和 L3 的提升</strong>。F1 从 0.85 升到 0.88 在技术上很有意义，但如果业务指标没变化——这个优化可能就不值得投入。</p><h3 id="_4-2-在线-vs-离线评估" tabindex="-1">4.2 在线 vs 离线评估 <a class="header-anchor" href="#_4-2-在线-vs-离线评估" aria-label="Permalink to &quot;4.2 在线 vs 离线评估&quot;">​</a></h3><table tabindex="0"><thead><tr><th>评估方式</th><th>方法</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td><strong>离线评估</strong></td><td>在固定的测试集上计算指标</td><td>快、可复现、便宜</td><td>不能真实反映线上效果</td></tr><tr><td><strong>在线评估</strong></td><td>A/B 测试对比线上真实表现</td><td>真实、全面</td><td>慢、成本高、需要真实流量</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">实战经验</p><p>离线评估 0.05 的指标提升在线上可能完全看不到效果。反过来，离线评估看起来没提升的改动（比如改了一个 Prompt 的措辞），在线上可能因为更匹配用户的实际表达方式而效果明显提升。<strong>永远以在线评估为准，离线评估只是筛掉明显不行的方案。</strong></p></div><hr><h2 id="五、ai-产品-prd-撰写规范" tabindex="-1">五、AI 产品 PRD 撰写规范 <a class="header-anchor" href="#五、ai-产品-prd-撰写规范" aria-label="Permalink to &quot;五、AI 产品 PRD 撰写规范&quot;">​</a></h2><h3 id="_5-1-ai-产品-prd-的结构" tabindex="-1">5.1 AI 产品 PRD 的结构 <a class="header-anchor" href="#_5-1-ai-产品-prd-的结构" aria-label="Permalink to &quot;5.1 AI 产品 PRD 的结构&quot;">​</a></h3><p>与传统 PRD 相比，AI 产品 PRD 新增了三个核心章节：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 产品概述</span></span>
<span class="line"><span>   - 产品定位与核心价值</span></span>
<span class="line"><span>   - 目标用户与使用场景</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 功能需求</span></span>
<span class="line"><span>   - 功能列表与优先级</span></span>
<span class="line"><span>   - 交互流程与原型</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 【新增】AI 模型需求</span></span>
<span class="line"><span>   - 模型输入定义（字段、格式、数据源）</span></span>
<span class="line"><span>   - 模型输出定义（格式、字段含义、置信度要求）</span></span>
<span class="line"><span>   - 性能基线要求（准确率/召回率/F1 最低阈值）</span></span>
<span class="line"><span>   - 推理速度要求（延迟上限、并发要求）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 【新增】数据需求</span></span>
<span class="line"><span>   - 训练/测试数据来源与规模</span></span>
<span class="line"><span>   - 标注规范概要（含边界 Case 定义）</span></span>
<span class="line"><span>   - 数据质量要求</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 【新增】评估与验收</span></span>
<span class="line"><span>   - 离线评估方案（评估集构建、评估指标）</span></span>
<span class="line"><span>   - 在线评估方案（A/B 测试设计、评价标准）</span></span>
<span class="line"><span>   - 上线标准（指标达标阈值）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 非功能性需求</span></span>
<span class="line"><span>   - 安全性、合规性、可观测性</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h3 id="_5-2-prd-撰写实战要点" tabindex="-1">5.2 PRD 撰写实战要点 <a class="header-anchor" href="#_5-2-prd-撰写实战要点" aria-label="Permalink to &quot;5.2 PRD 撰写实战要点&quot;">​</a></h3><p><strong>不要只写&quot;准确率 &gt; 90%&quot;</strong>——太笼统。要写清楚：</p><ul><li>在什么测试集上（&quot;包含 500 条真实业务场景的评测集，覆盖 10 个高频意图分类&quot;）</li><li>对什么指标（&quot;每个类别的召回率不低于 85%，整体 F1 不低于 90%&quot;）</li><li>什么条件下可以上线（&quot;在线 A/B 测试，处理量 &gt; 10000 次后，人工替代率提升 &gt; 15%&quot;）</li></ul><hr><h2 id="六、面试追问合集" tabindex="-1">六、面试追问合集 <a class="header-anchor" href="#六、面试追问合集" aria-label="Permalink to &quot;六、面试追问合集&quot;">​</a></h2><h3 id="q1-设计一个-ai-客服产品-你会怎么考虑降级策略" tabindex="-1">Q1: 设计一个 AI 客服产品，你会怎么考虑降级策略？ <a class="header-anchor" href="#q1-设计一个-ai-客服产品-你会怎么考虑降级策略" aria-label="Permalink to &quot;Q1: 设计一个 AI 客服产品，你会怎么考虑降级策略？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>核心思路是**&quot;模型能搞定的它搞定，搞不定的不装&quot;**。</p><p>我会设计三级降级策略：</p><p><strong>第一级：直接回答</strong>。用户问&quot;退货流程是什么&quot;，这个大概率模型的回答是准确的。如果模型的生成置信度 &gt; 95%，直接返回结果。</p><p><strong>第二级：知识库兜底</strong>。用户问&quot;我的订单 ORD-2024-0001 到哪了&quot;，这个可能需要精确信息检索。如果模型不确定，降级到知识库精确匹配——直接用向量检索 + Rerank，把匹配到的最相关文档拼接后呈现。</p><p><strong>第三级：人工接管</strong>。用户问&quot;你们这个产品太坑了，我已经投诉到 12345 了&quot;，这个涉及高风险。模型检测到高风险关键词（投诉/举报/12345/诉讼），直接转人工——不要让 AI 在高压场景下跟用户对话，翻车后果很严重。</p><p>关键设计原则是：<strong>每一级降级都要用不同的 UI 呈现，让用户感知到&quot;当前回答的来源和可信度&quot;不同。</strong> 直接回答用正常气泡，知识库兜底用&quot;以下信息来自帮助中心&quot;的标注，人工接管用&quot;正在为您转接人工客服&quot;的过渡态。</p></details><h3 id="q2-你怎么衡量一个-ai-产品-做好了" tabindex="-1">Q2: 你怎么衡量一个 AI 产品&quot;做好了&quot;？ <a class="header-anchor" href="#q2-你怎么衡量一个-ai-产品-做好了" aria-label="Permalink to &quot;Q2: 你怎么衡量一个 AI 产品&quot;做好了&quot;？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>三个维度交叉验证：</p><ol><li><strong>模型维度</strong>：离线指标达标（准确率、召回率等已超过基线阈值）</li><li><strong>业务维度</strong>：在线 A/B 测试证明核心业务指标有统计显著的提升——不只是&quot;提升了&quot;（可能只是随机波动），而是 p-value &lt; 0.05 的显著提升</li><li><strong>用户维度</strong>：满意度调研 + Bad Case 分析确认用户感知到的体验是正面的，而不是&quot;准确率高但用户觉得不好用&quot;</li></ol><p>一个经常被忽略的点：<strong>高质量 ≠ 高满意度</strong>。模型的 F1 很高，但用户可能觉得&quot;回答太啰嗦&quot;或&quot;太机械&quot;。只盯技术指标不看用户反馈是做 AI 产品最容易踩的坑。</p></details><h3 id="q3-如果模型的准确率卡住了就是上不去-你会怎么排查" tabindex="-1">Q3: 如果模型的准确率卡住了就是上不去，你会怎么排查？ <a class="header-anchor" href="#q3-如果模型的准确率卡住了就是上不去-你会怎么排查" aria-label="Permalink to &quot;Q3: 如果模型的准确率卡住了就是上不去，你会怎么排查？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>我的排查顺序是：</p><ol><li><strong>看 Bad Case 分布</strong>：是不是集中在某几类问题？如果 80% 的 Bad Case 来自同一个类别（比如&quot;模糊意图&quot;），那可能是标注数据在这个类别上不够多，或者标注规范里对这个类别的定义不够清晰。</li><li><strong>看数据质量</strong>：抽 100 条 Bad Case 回去看原始标注——标注本身可能有错误。我见过标注准确率只有 85% 的数据集去训模型，这个天花板就卡在那了。</li><li><strong>看线上线下 Gap</strong>：训练集和线上数据分布差多远？训练集可能是两个月前的数据，线上用户的表达方式已经变了。</li><li><strong>看模型能力上限</strong>：如果是模型本身的容量不够（比如用一个 BERT-base 去搞定非常复杂的多分类），不是调数据能解决的——得考虑升级模型或者把问题拆成多个子任务。</li></ol></details><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./tech-basics">AI 技术基础</a></li><li><a href="./data-model-management">数据与模型管理</a></li><li><a href="./prompt-engineering">Prompt 工程</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>`,29))])}const I=p(E,[["render",u]]);export{m as __pageData,I as default};
